#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 1000000
#define MAX_NAME 15

typedef struct Book {
    int exercises;
    char name[MAX_NAME + 1];
    int position;
} Book;

int compare(const void *a, const void *b) {
    Book *book1 = (Book *)a;
    Book *book2 = (Book *)b;
    if (book1->exercises != book2->exercises) {
        return book1->exercises - book2->exercises;
    } else {
        return book1->position - book2->position;
    }
}

int main() {
    int N;
    scanf("%d", &N);
    Book books[N];
    int top = 0;
    for (int i = 0; i < N; i++) {
        int exercises;
        scanf("%d", &exercises);
        if (exercises == -1) {
            qsort(books, top, sizeof(Book), compare);
            printf("%d %s\n", books[0].position, books[0].name);
            for (int j = 1; j < top; j++) {
                if (books[j].exercises == books[0].exercises) {
                    books[j].position--;
                }
            }
            top--;
        } else {
            char name[MAX_NAME + 1];
            scanf("%s", name);
            books[top].exercises = exercises;
            strcpy(books[top].name, name);
            books[top].position = top;
            top++;
        }
    }
    return 0;
}

