import java.util.PriorityQueue;
import java.util.Scanner;

public class Main {
    static class Book implements Comparable<Book> {
        int exercises;
        String name;
        int position;
        public Book(int exercises, String name, int position) {
            this.exercises = exercises;
            this.name = name;
            this.position = position;
        }
        @Override
        public int compareTo(Book other) {
            if (exercises != other.exercises) {
                return Integer.compare(exercises, other.exercises);
            } else {
                return Integer.compare(position, other.position);
            }
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        PriorityQueue<Book> pq = new PriorityQueue<>();
        for (int i = 0; i < N; i++) {
            int exercises = sc.nextInt();
            if (exercises == -1) {
                Book book = pq.poll();
                System.out.println(book.position + " " + book.name);
                while (!pq.isEmpty() && pq.peek().exercises == book.exercises) {
                    Book temp = pq.poll();
                    temp.position--;
                    pq.offer(temp);
                }
            } else {
                String name = sc.next();
                Book book = new Book(exercises, name, pq.size());
                pq.offer(book);
            }
        }
    }
}

