let idx = 0;

function nextInt() {
    return parseInt(lines[idx++]);
}

function nextString() {
    return lines[idx++];
}

class Book {
    constructor(exercises, name, position) {
        this.exercises = exercises;
        this.name = name;
        this.position = position;
    }
}

class PriorityQueue {
    constructor() {
        this.heap = [];
    }
    push(book) {
        this.heap.push(book);
        this.heap.sort((a, b) => a.exercises - b.exercises || a.position - b.position);
    }
    pop() {
        return this.heap.shift();
    }
    isEmpty() {
        return this.heap.length === 0;
    }
}

let N = nextInt();
let pq = new PriorityQueue();
